### Built-in Validators

Angular provides several built-in validators accessible via the `Validators` class:

```typescript
import { Validators } from '@angular/forms';

Validators.required                  // Field must have a value
Validators.email                     // Must be a valid email format
Validators.pattern('[a-zA-Z ]+')     // Must match regex
Validators.minLength(6)              // Minimum character count
Validators.maxLength(100)            // Maximum character count
Validators.min(0)                    // Minimum numeric value
Validators.max(100)                  // Maximum numeric value
Validators.requiredTrue              // Must be true (e.g., checkbox)
```

### Using Validators

```typescript
// Reactive Form
this.form = this.fb.group({
  name: ['', Validators.required],
  email: ['', [Validators.required, Validators.email]],
  age: [null, [Validators.min(18), Validators.max(120)]],
  password: ['', [Validators.required, Validators.minLength(8)]],
  agree: [false, Validators.requiredTrue]
});

// Template-Driven (using attributes)
// <input name="email" ngModel required email>
```

### Validation Messages

```html
<div *ngIf="form.get('email')?.invalid && form.get('email')?.touched">
  <p *ngIf="form.get('email')?.errors?.['required']">Email is required.</p>
  <p *ngIf="form.get('email')?.errors?.['email']">Enter a valid email.</p>
</div>
```

### Custom Validators

Create a function that returns either `null` (valid) or a validation error object:

```typescript
export function forbiddenNameValidator(forbidden: string): ValidatorFn {
  return (control: AbstractControl): ValidationErrors | null => {
    const forbiddenRegex = new RegExp(forbidden, 'i');
    return forbiddenRegex.test(control.value)
      ? { forbiddenName: { value: control.value } }
      : null;
  };
}

// Usage
this.form = this.fb.group({
  name: ['', [Validators.required, forbiddenNameValidator('admin')]]
});
```

### Cross-Field Validation

Validate across multiple fields using the FormGroup level:

```typescript
export const passwordMatchValidator: ValidatorFn = (group: AbstractControl): ValidationErrors | null => {
  const password = group.get('password')?.value;
  const confirm = group.get('confirmPassword')?.value;
  return password === confirm ? null : { passwordMismatch: true };
};

// Usage
this.form = this.fb.group({
  password: ['', Validators.required],
  confirmPassword: ['', Validators.required]
}, { validators: passwordMatchValidator });
```

### Async Validators

For server-side validation checks:

```typescript
export class UniqueEmailValidator implements AsyncValidatorFn {
  constructor(private userService: UserService) {}

  validate(control: AbstractControl): Observable<ValidationErrors | null> {
    return this.userService.checkEmail(control.value).pipe(
      map(isTaken => isTaken ? { emailTaken: true } : null),
      catchError(() => of(null))
    );
  }
}

// Usage
this.form = this.fb.group({
  email: ['', [Validators.required, Validators.email], [this.uniqueEmailValidator]]
});
```

Async validators are the third argument in the FormBuilder array syntax or in FormControl constructor.

codeExample:
// Custom validator
function forbiddenNameValidator(name: string): ValidatorFn {
  return (control: AbstractControl): ValidationErrors | null => {
    return control.value?.toLowerCase() === name.toLowerCase()
      ? { forbiddenName: { value: control.value } }
      : null;
  };
}

// Usage in reactive form
this.form = this.fb.group({
  username: ['', [Validators.required, forbiddenNameValidator('admin')]],
  email: ['', [Validators.required, Validators.email]],
  password: ['', Validators.minLength(8)]
});
